const ThemeContext = createContext("light");

function Label({ showTheme }) {
  if (showTheme) {
    const theme = use(ThemeContext); // 條件式呼叫
    return <span>目前主題：{theme}</span>;
  }
  return <span>不顯示主題</span>;
}

function App() {
  return (
    <ThemeContext.Provider value="dark">
      <Label showTheme={true} />
    </ThemeContext.Provider>
  );
}

console.log(renderToStaticMarkup(<App />));

